    /**
     * Get attributes for a specific HTML element, merged with common attributes.
     *
     * @return array<string, array{string, string}>  attrName => [type, description]
     */
    public static function forElement(string $tagName): array
    {
        return array_merge(
            self::COMMON,
            self::ELEMENT_SPECIFIC[$tagName] ?? [],
        );
